  def bulk_import
    uploaded_files = params[:config_files]
    
    if uploaded_files.blank?
      flash[:error] = "Please select at least one YAML file to upload"
      redirect_to configurations_path and return
    end

    imported_count = 0
    errors = []

    uploaded_files.each do |uploaded_file|
      begin
        config_data = YAML.safe_load(
          uploaded_file.read,
          permitted_classes: [Symbol, Date, Time, DateTime, ActiveSupport::TimeWithZone, ActiveSupport::TimeZone, BigDecimal],
          permitted_symbols: [],
          aliases: true,
          filename: uploaded_file.original_filename
        )
        
        configuration = Configuration.new(
          name: uploaded_file.original_filename,
          data: config_data,
          user_id: current_user.id,
          filename: uploaded_file.original_filename
        )
        
        if configuration.save
          imported_count += 1
        else
          errors << "#{uploaded_file.original_filename}: #{configuration.errors.full_messages.join(', ')}"
        end
      rescue Psych::SyntaxError => e
        errors << "#{uploaded_file.original_filename}: Invalid YAML syntax - #{e.message}"
      rescue => e
        errors << "#{uploaded_file.original_filename}: #{e.message}"
      end
    end

    if imported_count > 0
      flash[:success] = "Successfully imported #{imported_count} configuration(s)"
    end
    
    if errors.any?
      flash[:error] = "Errors encountered: #{errors.join('; ')}"
    end

    redirect_to configurations_path
  end

  def validate
    uploaded_file = params[:config_file]
    
    if uploaded_file.blank?
      render json: { valid: false, error: "No file provided" }, status: :unprocessable_entity
      return
    end

    begin
      config_data = YAML.safe_load(
        uploaded_file.read,
        permitted_classes: [Symbol, Date, Time, DateTime, ActiveSupport::TimeWithZone, ActiveSupport::TimeZone, BigDecimal],
        permitted_symbols: [],
        aliases: true,
