    rescue Psych::SyntaxError => e
      render json: { valid: false, error: "Invalid YAML syntax: #{e.message}" }, status: :unprocessable_entity
    rescue => e
      render json: { valid: false, error: "Error processing file: #{e.message}" }, status: :unprocessable_entity
    end
  end

